(function($){'use strict';window.deleteItem = function(itemType,itemId,itemName,redirectUrl){const messages ={'customers':{title:'حذف زبون',text:'سيتم إلغاء تفعيل الزبون وليس حذفه نهائياً',url:`/customers/${itemId}/delete`},'suppliers':{title:'حذف مورد',text:'سيتم إلغاء تفعيل المورد وليس حذفه نهائياً',url:`/suppliers/${itemId}/delete`},'products':{title:'حذف منتج',text:'سيتم إلغاء تفعيل المنتج وليس حذفه نهائياً',url:`/products/${itemId}/delete`},'sales':{title:'إلغاء فاتورة',text:'سيتم إلغاء الفاتورة والحفاظ على السجلات المالية',url:`/sales/${itemId}/cancel`},'purchases':{title:'حذف فاتورة شراء',text:'سيتم أرشفة الفاتورة والحفاظ على السجلات المالية',url:`/purchases/${itemId}/delete`},'receipts':{title:'حذف سند قبض',text:'سيتم إلغاء السند والحفاظ على السجلات المالية',url:`/payments/receipts/${itemId}/delete`},'expenses':{title:'حذف مصروف',text:'سيتم إلغاء المصروف والحفاظ على السجلات المالية',url:`/expenses/${itemId}/delete`},'cheques':{title:'أرشفة شيك',text:'سيتم أرشفة الشيك والحفاظ على السجلات',url:`/cheques/${itemId}/delete`},'users':{title:'حذف مستخدم',text:'سيتم إلغاء تفعيل المستخدم وليس حذفه نهائياً',url:`/owner/users/${itemId}/delete`}};const msg = messages[itemType] ||{title:'حذف',text:'هل أنت متأكد من الحذف؟',url:`/${itemType}/${itemId}/delete`};Swal.fire({title:msg.title,html:` <p><strong>${itemName}</strong></p> <p class="text-muted">${msg.text}</p> `,icon:'warning',showCancelButton:true,confirmButtonColor:'#d33',cancelButtonColor:'#6c757d',confirmButtonText:'<i class="fas fa-trash mr-2"></i>نعم، احذف',cancelButtonText:'<i class="fas fa-times mr-2"></i>إلغاء',reverseButtons:true,showLoaderOnConfirm:true,preConfirm:function(){const form = document.createElement('form');form.method = 'POST';form.action = msg.url;const csrfInput = document.createElement('input');csrfInput.type = 'hidden';csrfInput.name = 'csrf_token';csrfInput.value = document.querySelector('input[name="csrf_token"]')?.value || document.querySelector('meta[name="csrf-token"]')?.getAttribute('content')|| '';form.appendChild(csrfInput);document.body.appendChild(form);form.submit();return new Promise(()=>{});},allowOutsideClick:()=> !Swal.isLoading()});};window.deleteMultiple = function(itemIds,itemType,redirectUrl){if(!itemIds || itemIds.length === 0){toastr.warning('⚠️ يجب اختيار عنصر واحد على الأقل');return;}Swal.fire({title:'حذف متعدد',html:` <p>سيتم حذف <strong>${itemIds.length}</strong> عنصر</p> <p class="text-muted">سيتم أرشفة العناصر والحفاظ على السجلات المالية</p> `,icon:'warning',showCancelButton:true,confirmButtonColor:'#d33',cancelButtonColor:'#6c757d',confirmButtonText:'<i class="fas fa-trash mr-2"></i>نعم، احذف الكل',cancelButtonText:'<i class="fas fa-times mr-2"></i>إلغاء',reverseButtons:true,showLoaderOnConfirm:true,preConfirm:function(){return $.ajax({url:`/${itemType}s/delete-multiple`,method:'POST',data:JSON.stringify({ids:itemIds}),contentType:'application/json',headers:{'X-CSRFToken':$('input[name="csrf_token"]').val()|| $('meta[name="csrf-token"]').attr('content')}}).then(function(response){return response;}).catch(function(error){Swal.showValidationMessage(`حدث خطأ:${error.responseJSON?.message || 'خطأ غير معروف'}`);});},allowOutsideClick:()=> !Swal.isLoading()}).then(function(result){if(result.isConfirmed){Swal.fire({icon:'success',title:'تم الحذف بنجاح',text:`تم حذف ${itemIds.length}عنصر بنجاح`,timer:2000,showConfirmButton:false}).then(function(){if(redirectUrl){window.location.href = redirectUrl;}else{location.reload();}});}});};window.deleteTableRow = function(rowElement,confirmMessage = 'هل أنت متأكد من الحذف؟'){Swal.fire({title:'تأكيد الحذف',text:confirmMessage,icon:'warning',showCancelButton:true,confirmButtonColor:'#d33',cancelButtonColor:'#6c757d',confirmButtonText:'<i class="fas fa-trash mr-2"></i>نعم',cancelButtonText:'<i class="fas fa-times mr-2"></i>إلغاء',reverseButtons:true}).then(function(result){if(result.isConfirmed){$(rowElement).fadeOut(300,function(){$(this).remove();toastr.success('✅ تم الحذف');});}});};window.restoreItem = function(itemId,itemType,itemName){Swal.fire({title:'استعادة العنصر',html:`<p>هل تريد استعادة:<strong>${itemName}</strong>؟</p>`,icon:'question',showCancelButton:true,confirmButtonColor:'#28a745',cancelButtonColor:'#6c757d',confirmButtonText:'<i class="fas fa-undo mr-2"></i>نعم، استعد',cancelButtonText:'<i class="fas fa-times mr-2"></i>إلغاء',reverseButtons:true,showLoaderOnConfirm:true,preConfirm:function(){return $.ajax({url:`/${itemType}s/${itemId}/restore`,method:'POST',headers:{'X-CSRFToken':$('input[name="csrf_token"]').val()|| $('meta[name="csrf-token"]').attr('content')}}).then(function(response){return response;}).catch(function(error){Swal.showValidationMessage(`حدث خطأ:${error.responseJSON?.message || 'خطأ غير معروف'}`);});},allowOutsideClick:()=> !Swal.isLoading()}).then(function(result){if(result.isConfirmed){Swal.fire({icon:'success',title:'تمت الاستعادة',text:'تم استعادة العنصر بنجاح',timer:2000,showConfirmButton:false}).then(function(){location.reload();});}});};$(document).on('click','[data-delete-item]',function(e){e.preventDefault();const $btn = $(this);const itemId = $btn.data('delete-item');const itemType = $btn.data('item-type');const itemName = $btn.data('item-name')|| 'هذا العنصر';const redirectUrl = $btn.data('redirect-url');deleteItem(itemId,itemType,itemName,redirectUrl);});$(document).on('click','[data-delete-row]',function(e){e.preventDefault();const $btn = $(this);const rowElement = $btn.closest('tr,.product-line,[data-row]');const confirmMessage = $btn.data('confirm-message')|| 'هل أنت متأكد من حذف هذا السطر؟';deleteTableRow(rowElement,confirmMessage);});$(document).on('click','[data-restore-item]',function(e){e.preventDefault();const $btn = $(this);const itemId = $btn.data('restore-item');const itemType = $btn.data('item-type');const itemName = $btn.data('item-name')|| 'هذا العنصر';restoreItem(itemId,itemType,itemName);});})(jQuery);